// Role constants with explicit hierarchy
type Role int

const (
	RolePlayer Role = iota
	RoleModerator
	RoleAdmin
	RoleSuperAdmin
)

func (r Role) String() string {
	switch r {
	case RolePlayer:
		return "player"
	case RoleModerator:
		return "moderator"
	case RoleAdmin:
		return "admin"
	case RoleSuperAdmin:
		return "superadmin"
	default:
		return "unknown"
	}
}

