func (s *UserStore) GetUser(username string) (*User, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[username]
	return u, ok
}

func (s *UserStore) SetBan(username string, banned bool, reason string, duration time.Duration) bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	u, ok := s.users[username]
	if !ok {
		return false
	}
	u.Banned = banned
	u.BanReason = reason
	if banned && duration > 0 {
		u.BanExpiry = time.Now().Add(duration)
	} else if banned {
		u.BanExpiry = time.Now().Add(100 * 365 * 24 * time.Hour) // permanent
	} else {
		u.BanExpiry = time.Time{}
	}
	return true
}

func (s *UserStore) IsBanned(username string) (bool, string) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[username]
	if !ok {
		return false, ""
	}
	if u.Banned {
		if !u.BanExpiry.IsZero() && time.Now().After(u.BanExpiry) {
			// Ban expired - clear it (need write lock)
			s.mu.RUnlock()
			s.mu.Lock()
			u.Banned = false
			u.BanReason = ""
			u.BanExpiry = time.Time{}
			s.mu.Unlock()
			s.mu.RLock()
			return false, ""
		}
		return true, u.BanReason
	}
	return false, ""
}

// SessionManager manages active sessions with server-generated tokens
type SessionManager struct {
	mu       sync.RWMutex
	sessions map[string]*User // session token -> user
}

func NewSessionManager() *SessionManager {
	return &SessionManager{
		sessions: make(map[string]*User),
	}
}

func (sm *SessionManager) CreateSession(user *User) string {
	sm.mu.Lock()
	defer sm.mu.Unlock()

	token := generateSecureToken()
	user.SessionID = token
	sm.sessions[token] = user
	return token
}

func (sm *SessionManager) GetSession(token string) (*User, bool) {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	u, ok := sm.sessions[token]
	return u, ok
}

func (sm *SessionManager) RemoveSession(token string) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	delete(sm.sessions, token)
}

func generateSecureToken() string {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		log.Fatal("failed to generate secure token:", err)
	}
	return hex.EncodeToString(b)
}

