// ClientMessage represents a message from the client
type ClientMessage struct {
	Type string `json:"type"` // "auth", "chat", "command"
	// Auth fields
	Username string `json:"username,omitempty"`
	Password string `json:"password,omitempty"`
	// Chat/command fields
	SessionToken string `json:"session_token,omitempty"`
	Content      string `json:"content,omitempty"`
	// NOTE: We intentionally do NOT accept a "role" field from the client.
	// Any client-provided role information is IGNORED.
	// The following field exists to demonstrate that we reject it:
	ClaimedRole string `json:"claimed_role,omitempty"` // IGNORED - for demonstration
}

type ServerMessage struct {
	Type    string `json:"type"`
	Content string `json:"content"`
	Success bool   `json:"success"`
}

func (gs *GameServer) Start(address string) error {
	var err error
	gs.listener, err = net.Listen("tcp", address)
	if err != nil {
		return fmt.Errorf("failed to start server: %w", err)
	}
	log.Printf("Game server started on %s", address)

	for {
		conn, err := gs.listener.Accept()
		if err != nil {
			log.Printf("Accept error: %v", err)
			continue
		}
		go gs.handleConnection(conn)
	}
}

func (gs *GameServer) handleConnection(conn net.Conn) {
	defer conn.Close()
	scanner := bufio.NewScanner(conn)
	var authenticatedUser *User

	sendMessage := func(msgType, content string, success bool) {
		msg := ServerMessage{Type: msgType, Content: content, Success: success}
		data, _ := json.Marshal(msg)
		fmt.Fprintf(conn, "%s\n", data)
	}

	for scanner.Scan() {
		line := scanner.Text()
		var clientMsg ClientMessage
		if err := json.Unmarshal([]byte(line), &clientMsg); err != nil {
			sendMessage("error", "Invalid message format", false)
			continue
		}

		switch clientMsg.Type {
		case "auth":
			user := gs.authenticateUser(clientMsg.Username, clientMsg.Password, clientMsg.ClaimedRole, conn)
			if user == nil {
				sendMessage("auth", "Authentication failed", false)
				continue
			}
			authenticatedUser = user
			sendMessage("auth", fmt.Sprintf("Authenticated as %s (role: %s, session: %s)",
				user.Username, user.Role.String(), user.SessionID), true)

		case "chat", "command":
			if authenticatedUser == nil {
				sendMessage("error", "Not authenticated", false)
				continue
			}
			// Verify session is still valid
			sessionUser, ok := gs.sessionManager.GetSession(authenticatedUser.SessionID)
			if !ok || sessionUser.Username != authenticatedUser.Username {
				sendMessage("error", "Session expired", false)
				authenticatedUser = nil
				continue
			}

			content := clientMsg.Content

			// SECURITY: Re-fetch the user's role from the server-side store
			// NEVER trust the client's claimed role
			serverUser, exists := gs.userStore.GetUser(authenticatedUser.Username)
			if !exists {
				sendMessage("error", "User no longer exists", false)
				continue
			}
			// Use the server-authoritative role
			authenticatedUser.Role = serverUser.Role

			if strings.HasPrefix(content, "/") {
				gs.handleCommand(authenticatedUser, content, sendMessage)
			} else {
				// Regular chat message
				log.Printf("[CHAT] %s: %s", authenticatedUser.Username, content)
				sendMessage("chat", fmt.Sprintf("[%s] %s: %s",
					authenticatedUser.Role.String(), authenticatedUser.Username, content), true)
			}

		default:
			sendMessage("error", "Unknown message type", false)
		}
	}

	// Cleanup on disconnect
	if authenticatedUser != nil {
		gs.sessionManager.RemoveSession(authenticatedUser.SessionID)
		gs.connectedUsers.Delete(authenticatedUser.Username)
		log.Printf("User %s disconnected", authenticatedUser.Username)
	}
}

func (gs *GameServer) authenticateUser(username, password, claimedRole string, conn net.Conn) *User {
	// SECURITY: Log if client attempts to claim a role
	if claimedRole != "" {
		log.Printf("[SECURITY WARNING] Client for user '%s' attempted to claim role '%s' - IGNORED",
			username, claimedRole)
		gs.auditLog.Log(AuditEntry{
			Actor:   username,
			Action:  "ROLE_CLAIM_ATTEMPT",
			Details: fmt.Sprintf("Client attempted to claim role: %s", claimedRole),
			Success: false,
		})
		// We do NOT use the claimed role. We look up the server-side role.
	}

	// Check if user exists in our server-side store
	serverUser, exists := gs.userStore.GetUser(username)
	if !exists {
		log.Printf("Authentication failed: unknown user '%s'", username)
		return nil
	}

	// In production, verify password against hashed password in database
	// For this demo, we accept any non-empty password
	if password == "" {
		log.Printf("Authentication failed: empty password for user '%s'", username)
		return nil
	}

	// Check if user is banned
	if banned, reason := gs.userStore.IsBanned(username); banned {
		log.Printf("Authentication failed: user '%s' is banned: %s", username, reason)
		return nil
	}

	// Create a session with the SERVER-AUTHORITATIVE role
	user := &User{
		ID:       serverUser.ID,
		Username: serverUser.Username,
		Role:     serverUser.Role, // FROM SERVER, not from client
		Conn:     conn,
	}

	sessionToken := gs.sessionManager.CreateSession(user)
	user.SessionID = sessionToken
	gs.connectedUsers.Store(username, user)

	gs.auditLog.Log(AuditEntry{
		Actor:     username,
		ActorRole: user.Role.String(),
		Action:    "LOGIN",
		Details:   fmt.Sprintf("Authenticated with server role: %s", user.Role.String()),
		Success:   true,
	})

	log.Printf("User '%s' authenticated with server-assigned role: %s", username, user.Role.String())
	return user
}

func (gs *GameServer) handleCommand(user *User, content string, sendMessage func(string, string, bool)) {
	// Parse command
	parts := strings.Fields(content)
	if len(parts) == 0 {
		return
	}

	cmd := Command{
		Name: strings.ToLower(parts[0]),
		Args: parts[1:],
	}

	// Rate limiting
	if !gs.rateLimiter.Allow(user.ID) {
		sendMessage("error", "Rate limited: too many commands", false)
		gs.auditLog.Log(AuditEntry{
			Actor:     user.Username,
			ActorRole: user.Role.String(),
			Action:    "RATE_LIMITED",
			Details:   cmd.Name,
			Success:   false,
		})
		return
	}

	// Check if command exists
	requiredRole, exists := CommandPermissions[cmd.Name]
	if !exists {
		sendMessage("error", fmt.Sprintf("Unknown command: %s", cmd.Name), false)
		return
	}

	// SECURITY: Check permission using SERVER-SIDE role
	// Re-fetch from store to ensure we have the latest role
	serverUser, userExists := gs.userStore.GetUser(user.Username)
	if !userExists {
		sendMessage("error", "User no longer exists", false)
		return
	}

	currentRole := serverUser.Role // SERVER-AUTHORITATIVE role

	if currentRole < requiredRole {
		sendMessage("error", fmt.Sprintf("Permission denied: %s requires %s role (you are %s)",
			cmd.Name, requiredRole.String(), currentRole.String()), false)
		gs.auditLog.Log(AuditEntry{
			Actor:     user.Username,
			ActorRole: currentRole.String(),
			Action:    "PERMISSION_DENIED",
			Details:   fmt.Sprintf("Attempted %s, requires %s", cmd.Name, requiredRole.String()),
			Success:   false,
		})
		return
	}

	// Execute command
	switch cmd.Name {
	case "/kick":
		gs.cmdKick(user, currentRole, cmd.Args, sendMessage)
	case "/ban":
		gs.cmdBan(user, currentRole, cmd.Args, sendMessage)
	case "/unban":
		gs.cmdUnban(user, currentRole, cmd.Args, sendMessage)
	case "/giveitems":
		gs.cmdGiveItems(user, currentRole, cmd.Args, sendMessage)
	case "/mute":
		gs.cmdMute(user, currentRole, cmd.Args, sendMessage)
	case "/announce":
		gs.cmdAnnounce(user, currentRole, cmd.Args, sendMessage)
	case "/shutdown":
		gs.cmdShutdown(user, currentRole, cmd.Args, sendMessage)
	case "/setrole":
		gs.cmdSetRole(user, currentRole, cmd.Args, sendMessage)
	default:
		sendMessage("error", "Command not implemented", false)
	}
}

func (gs *GameServer) cmdKick(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	if len(args) < 1 {
		sendMessage("error", "Usage: /kick <username> [reason]", false)
		return
	}

	targetUsername := args[0]
	reason := "No reason provided"
	if len(args) > 1 {
		reason = strings.Join(args[1:], " ")
	}

	// Prevent kicking yourself
	if targetUsername == actor.Username {
		sendMessage("error", "Cannot kick yourself", false)
		return
	}

	// SECURITY: Prevent privilege escalation - can't kick users with equal or higher role
	targetUser, exists := gs.userStore.GetUser(targetUsername)
	if !exists {
		sendMessage("error", fmt.Sprintf("User '%s' not found", targetUsername), false)
		return
	}

	if targetUser.Role >= actorRole {
		sendMessage("error", fmt.Sprintf("Cannot kick %s: their role (%s) is equal or higher than yours (%s)",
			targetUsername, targetUser.Role.String(), actorRole.String()), false)
		gs.auditLog.Log(AuditEntry{
			Actor:     actor.Username,
			ActorRole: actorRole.String(),
			Action:    "KICK_DENIED",
			Target:    targetUsername,
			Details:   "Target has equal or higher role",
			Success:   false,
		})
		return
	}

	// Perform kick
	if connUser, ok := gs.connectedUsers.Load(targetUsername); ok {
		if u, ok := connUser.(*User); ok && u.Conn != nil {
			kickMsg := ServerMessage{Type: "kicked", Content: fmt.Sprintf("You have been kicked: %s", reason)}
			data, _ := json.Marshal(kickMsg)
			fmt.Fprintf(u.Conn, "%s\n", data)
			u.Conn.Close()
		}
		gs.connectedUsers.Delete(targetUsername)
	}

	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "KICK",
		Target:    targetUsername,
		Details:   reason,
		Success:   true,
	})

	sendMessage("command", fmt.Sprintf("Kicked user '%s': %s", targetUsername, reason), true)
}

func (gs *GameServer) cmdBan(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	if len(args) < 1 {
		sendMessage("error", "Usage: /ban <username> [duration_minutes] [reason]", false)
		return
	}

	targetUsername := args[0]
	reason := "No reason provided"
	duration := time.Duration(0) // permanent by default

	if len(args) > 1 {
		// Try to parse duration
		var minutes int
		if _, err := fmt.Sscanf(args[1], "%d", &minutes); err == nil && minutes > 0 {
			duration = time.Duration(minutes) * time.Minute
			if len(args) > 2 {
				reason = strings.Join(args[2:], " ")
			}
		} else {
			reason = strings.Join(args[1:], " ")
		}
	}

	// Prevent banning yourself
	if targetUsername == actor.Username {
		sendMessage("error", "Cannot ban yourself", false)
		return
	}

	// SECURITY: Prevent privilege escalation
	targetUser, exists := gs.userStore.GetUser(targetUsername)
	if !exists {
		sendMessage("error", fmt.Sprintf("User '%s' not found", targetUsername), false)
		return
	}

	if targetUser.Role >= actorRole {
		sendMessage("error", fmt.Sprintf("Cannot ban %s: their role (%s) is equal or higher than yours (%s)",
			targetUsername, targetUser.Role.String(), actorRole.String()), false)
		gs.auditLog.Log(AuditEntry{
			Actor:     actor.Username,
			ActorRole: actorRole.String(),
			Action:    "BAN_DENIED",
			Target:    targetUsername,
			Details:   "Target has equal or higher role",
			Success:   false,
		})
		return
	}

	// Apply ban
	gs.userStore.SetBan(targetUsername, true, reason, duration)

	// Kick if online
	if connUser, ok := gs.connectedUsers.Load(targetUsername); ok {
		if u, ok := connUser.(*User); ok && u.Conn != nil {
			banMsg := ServerMessage{Type: "banned", Content: fmt.Sprintf("You have been banned: %s", reason)}
			data, _ := json.Marshal(banMsg)
			fmt.Fprintf(u.Conn, "%s\n", data)
			u.Conn.Close()
		}
		gs.connectedUsers.Delete(targetUsername)
	}

	durationStr := "permanent"
	if duration > 0 {
		durationStr = duration.String()
	}

	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "BAN",
		Target:    targetUsername,
		Details:   fmt.Sprintf("Duration: %s, Reason: %s", durationStr, reason),
		Success:   true,
	})

	sendMessage("command", fmt.Sprintf("Banned user '%s' (%s): %s", targetUsername, durationStr, reason), true)
}

func (gs *GameServer) cmdUnban(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	if len(args) < 1 {
		sendMessage("error", "Usage: /unban <username>", false)
		return
	}

	targetUsername := args[0]

	if !gs.userStore.SetBan(targetUsername, false, "", 0) {
		sendMessage("error", fmt.Sprintf("User '%s' not found", targetUsername), false)
		return
	}

	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "UNBAN",
		Target:    targetUsername,
		Success:   true,
	})

	sendMessage("command", fmt.Sprintf("Unbanned user '%s'", targetUsername), true)
}

func (gs *GameServer) cmdGiveItems(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	if len(args) < 2 {
		sendMessage("error", "Usage: /giveitems <username> <item_id> [quantity]", false)
		return
	}

	targetUsername := args[0]
	itemID := args[1]
	quantity := "1"
	if len(args) > 2 {
		quantity = args[2]
	}

	// Validate target exists
	_, exists := gs.userStore.GetUser(targetUsername)
	if !exists {
		sendMessage("error", fmt.Sprintf("User '%s' not found", targetUsername), false)
		return
	}

	// Sanitize item ID - only allow alphanumeric and underscores
	for _, c := range itemID {
		if !((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9') || c == '_') {
			sendMessage("error", "Invalid item ID format", false)
			return
		}
	}

	// In a real game, this would add items to the player's inventory
	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "GIVE_ITEMS",
		Target:    targetUsername,
		Details:   fmt.Sprintf("Item: %s, Quantity: %s", itemID, quantity),
		Success:   true,
	})

	sendMessage("command", fmt.Sprintf("Gave %s x%s to '%s'", itemID, quantity, targetUsername), true)
}

func (gs *GameServer) cmdMute(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	if len(args) < 1 {
		sendMessage("error", "Usage: /mute <username> [duration_minutes]", false)
		return
	}

	targetUsername := args[0]

	// SECURITY: Prevent privilege escalation
	targetUser, exists := gs.userStore.GetUser(targetUsername)
	if !exists {
		sendMessage("error", fmt.Sprintf("User '%s' not found", targetUsername), false)
		return
	}

	if targetUser.Role >= actorRole {
		sendMessage("error", "Cannot mute a user with equal or higher role", false)
		return
	}

	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "MUTE",
		Target:    targetUsername,
		Success:   true,
	})

	sendMessage("command", fmt.Sprintf("Muted user '%s'", targetUsername), true)
}

func (gs *GameServer) cmdAnnounce(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	if len(args) < 1 {
		sendMessage("error", "Usage: /announce <message>", false)
		return
	}

	message := strings.Join(args, " ")

	// Broadcast to all connected users
	gs.connectedUsers.Range(func(key, value interface{}) bool {
		if u, ok := value.(*User); ok && u.Conn != nil {
			announceMsg := ServerMessage{
				Type:    "announcement",
				Content: fmt.Sprintf("[ANNOUNCEMENT from %s] %s", actor.Username, message),
				Success: true,
			}
			data, _ := json.Marshal(announceMsg)
			fmt.Fprintf(u.Conn, "%s\n", data)
		}
		return true
	})

	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "ANNOUNCE",
		Details:   message,
		Success:   true,
	})

	sendMessage("command", "Announcement sent", true)
}

func (gs *GameServer) cmdShutdown(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "SHUTDOWN",
		Details:   "Server shutdown initiated",
		Success:   true,
	})

	// Notify all users
	gs.connectedUsers.Range(func(key, value interface{}) bool {
		if u, ok := value.(*User); ok && u.Conn != nil {
			shutdownMsg := ServerMessage{
				Type:    "shutdown",
				Content: "Server is shutting down",
				Success: true,
			}
			data, _ := json.Marshal(shutdownMsg)
			fmt.Fprintf(u.Conn, "%s\n", data)
			u.Conn.Close()
		}
		return true
	})

	sendMessage("command", "Server shutdown initiated", true)
	log.Println("Server shutdown initiated by", actor.Username)
	os.Exit(0)
}

func (gs *GameServer) cmdSetRole(actor *User, actorRole Role, args []string, sendMessage func(string, string, bool)) {
	if len(args) < 2 {
		sendMessage("error", "Usage: /setrole <username> <role>", false)
		return
	}

	targetUsername := args[0]
	newRoleStr := strings.ToLower(args[1])

	// Parse the requested role
	var newRole Role
	switch newRoleStr {
	case "player":
		newRole = RolePlayer
	case "moderator":
		newRole = RoleModerator
	case "admin":
		newRole = RoleAdmin
	default:
		sendMessage("error", "Invalid role. Valid roles: player, moderator, admin", false)
		return
	}

	// SECURITY: Cannot set role to SuperAdmin
	if newRole >= RoleSuperAdmin {
		sendMessage("error", "Cannot assign superadmin role", false)
		return
	}

	// SECURITY: Cannot set role equal to or higher than your own (unless you're superadmin)
	if newRole >= actorRole && actorRole != RoleSuperAdmin {
		sendMessage("error", "Cannot assign a role equal to or higher than your own", false)
		return
	}

	// SECURITY: Cannot modify users with equal or higher role
	targetUser, exists := gs.userStore.GetUser(targetUsername)
	if !exists {
		sendMessage("error", fmt.Sprintf("User '%s' not found", targetUsername), false)
		return
	}

	if targetUser.Role >= actorRole {
		sendMessage("error", "Cannot modify role of user with equal or higher role", false)
		gs.auditLog.Log(AuditEntry{
			Actor:     actor.Username,
			ActorRole: actorRole.String(),
			Action:    "SETROLE_DENIED",
			Target:    targetUsername,
			Details:   fmt.Sprintf("Attempted to set role to %s, target has role %s", newRoleStr, targetUser.Role.String()),
			Success:   false,
		})
		return
	}

	// Apply role change (server-side)
	gs.userStore.mu.Lock()
	targetUser.Role = newRole
	gs.userStore.mu.Unlock()

	gs.auditLog.Log(AuditEntry{
		Actor:     actor.Username,
		ActorRole: actorRole.String(),
		Action:    "SETROLE",
		Target:    targetUsername,
		Details:   fmt.Sprintf("Role changed to %s", newRoleStr),
		Success:   true,
	})

	sendMessage("command", fmt.Sprintf("Set role of '%s' to %s", targetUsername, newRoleStr), true)
}

func main() {
	server := NewGameServer()

	fmt.Println("=== Game Server with Secure Admin Commands ===")
	fmt.Println()
	fmt.Println("SECURITY NOTES:")
	fmt.Println("- User roles are stored and validated SERVER-SIDE only")
	fmt.Println("- Client-provided role claims are IGNORED and logged as security events")
	fmt.Println("- All admin actions are audit-logged")
	fmt.Println("- Privilege escalation is prevented (can't affect users with >= role)")
	fmt.Println("- Rate limiting is applied to all commands")
	fmt.Println()
	fmt.Println("Pre-configured users (use any non-empty password):")
	fmt.Println("  superadmin - SuperAdmin role")
	fmt.Println("  admin1     - Admin role")
	fmt.Println("  mod1       - Moderator role")
	fmt.Println("  player1    - Player role")
	fmt.Println("  player2    - Player role")
	fmt.Println()
	fmt.Println("Connect with: nc localhost 9090")
	fmt.Println("Then send JSON messages, e.g.:")
	fmt.Println(`  {"type":"auth","username":"admin1","password":"pass"}`)
	fmt.Println(`  {"type":"command","content":"/kick player1 being rude"}`)
	fmt.Println()

	log.Fatal(server.Start(":9090"))
}